import "./EmployeeDetails.css";
import { useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";

// ✅ import role helpers (path is correct because auth.js is in Dashboard folder)
import { isAdmin, isEmployee, getLoggedInUser } from "../auth";

function EmployeeDetails() {
  const navigate = useNavigate();
  const [employees, setEmployees] = useState([]);

  // Load employees from localStorage
  useEffect(() => {
    const storedEmployees =
      JSON.parse(localStorage.getItem("employees")) || [];
    setEmployees(storedEmployees);
  }, []);

  // ✅ Get logged in user
  const user = getLoggedInUser();

  // ✅ EMPLOYEE should only see his own record
  const filteredEmployees = isEmployee()
    ? employees.filter((emp) => emp.email === user?.email)
    : employees;

  return (
    <div className="employee-page">
      {/* Title */}
      <h2 className="employee-title">Manage Employees</h2>

      {/* Top Actions */}
      <div className="employee-actions">
        <input
          type="text"
          placeholder="Search By Employee ID"
          className="search-box"
        />

        {/* ✅ ONLY ADMIN CAN SEE Add Button */}
        {isAdmin() && (
          <button
            className="add-btn"
            onClick={() => navigate("/dashboard/employee-details/add")}
          >
            Add New Employee
          </button>
        )}
      </div>

      {/* Employee Table */}
      <table className="employee-table">
        <thead>
          <tr>
            <th>S No</th>
            <th>Name</th>
            <th>DOB</th>
            <th>Department</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>
          {filteredEmployees.length > 0 ? (
            filteredEmployees.map((emp, index) => (
              <tr key={emp.id}>
                <td>{index + 1}</td>
                <td>{emp.name}</td>
                <td>{emp.dob}</td>
                <td>{emp.department}</td>

                <td className="actions">
                  {/* 👑 ADMIN BUTTONS */}
                  {isAdmin() && (
                    <>
                      <button
                        className="view"
                        onClick={() =>
                          navigate(
                            `/dashboard/employee-details/view/${emp.id}`
                          )
                        }
                      >
                        View
                      </button>

                      <button
                        className="edit"
                        onClick={() =>
                          navigate(
                            `/dashboard/employee-details/edit/${emp.id}`
                          )
                        }
                      >
                        Edit
                      </button>

                      <button
                        className="salary"
                        onClick={() =>
                          navigate(
                            `/dashboard/employee-details/salary/${emp.id}`,
                            {
                              state: { employee: emp },
                            }
                          )
                        }
                      >
                        Salary
                      </button>
                    </>
                  )}

                  {/* 👤 EMPLOYEE BUTTON */}
                  {isEmployee() && (
                    <button className="leave">
                      Leave
                    </button>
                  )}
                </td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="5" className="no-data">
                No Employees Found
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

export default EmployeeDetails;
